-
-pub inline fn Py_INCREF(op: *PyObject) void {
-    op.ob_refcnt += 1;
-}
-
-pub inline fn Py_DECREF(op: *PyObject) void {
-    op.ob_refcnt -= 1;
-    if (op.ob_refcnt == 0) {
-        if (op.ob_type.tp_dealloc) |dealloc| {
-            dealloc(op);
-        }
-    }
-}
-
-pub inline fn Py_XINCREF(op: ?*PyObject) void {
-    if (op) |o| Py_INCREF(o);
-}
-
-pub inline fn Py_XDECREF(op: ?*PyObject) void {
-    if (op) |o| Py_DECREF(o);
-}
