-// =============================================================================
-// Legacy Reference Counting (bridges to new CPython-compatible functions)
-// =============================================================================
-
-/// Legacy incref - bridges to Py_INCREF
-pub fn incref(obj: *PyObject) void {
-    Py_INCREF(obj);
-}
