-/// Repeat string n times (Python str * n)
-pub fn strRepeat(allocator: std.mem.Allocator, s: []const u8, n: usize) []const u8 {
-    if (n == 0) return "";
-    if (n == 1) return s;
-
-    const result = allocator.alloc(u8, s.len * n) catch return "";
-    for (0..n) |i| {
-        @memcpy(result[i * s.len ..][0..s.len], s);
-    }
-    return result;
